      contentType: 'application/json',
      body: JSON.stringify({ ok: true, revision, elements, violations: [] }),
    });
  });
  await page.route('**/api/family-catalogs/bathroom-fixtures', async (route) => {
    await route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify(catalogPayload),
